import styles from './Sidebar.module.css'

import EditObject from './FigureEditor';

function Sidebar({
    newObject,
    doubleClickedObjId,
    setDoubleClickedObjId,
    objects,
    setObjects,
    clips,
    setClips,
}) {
    return (
        <aside className={styles.sidebar}>
            <button onClick={newObject}>Add figure</button>
            {doubleClickedObjId ? (
                <EditObject
                    doubleClickedObjId={doubleClickedObjId}
                    setDoubleClickedObjId={setDoubleClickedObjId}
                    objects={objects}
                    setObjects={setObjects}
                />
            ) : (
                <div className={styles.noneSelected}>
                    <p>Select an object to edit</p>
                </div>
            )}
        </aside>
    );
}

export default Sidebar;
